import json
from bottle import run, route, request

@route('/api/user', method='GET')
def get_user():
    user_data = {
        'id': 1,
        'name': 'John Doe',
        'email': 'johndoe@example.com'
    }
    
    return json.dumps(user_data)

run(host='0.0.0.0', port=8000, server='waitress')

